// NewNfcAdapterStub creates a server-side INfcAdapter wrapping the given
// server implementation. The returned value satisfies INfcAdapter
// and can be passed to proxy methods; its AsBinder() returns a
// *binder.StubBinder that is auto-registered with the binder
// driver on first use.
func NewNfcAdapterStub(
	impl INfcAdapterServer,
) INfcAdapter {
	wrapper := &nfcAdapterStubWrapper{impl: impl}
	stub := &NfcAdapterStub{Impl: wrapper}
	wrapper.stubBinder = binder.NewStubBinder(stub)
	return wrapper
}
